import 'package:meta/meta.dart';

import 'prediction_mode.dart';
import 'prediction_state.dart';
import 'prediction_type.dart';

/// Represents temperature prediction information from a probe.
///
/// This class contains prediction data generated by the probe's prediction system, including estimated time to reach
/// target temperature, cooking progress, and prediction state information. Predictions are only available after a
/// target temperature has been set using `DeviceManager.setTargetTemperature`.
///
/// The prediction system uses the probe's temperature sensors and internal algorithms to estimate when food will reach
/// the target temperature, accounting for current cooking rate and temperature trends.
@immutable
class PredictionInfo {
  /// The estimated time in seconds until the food reaches the target temperature.
  ///
  /// Returns null if no prediction is available or if the target temperature has already been reached.
  final int? estimatedTimeSeconds;

  /// The target temperature in Celsius that was set for this prediction.
  ///
  /// This is the temperature the probe is predicting the food will reach based on current cooking conditions and
  /// temperature trends.
  final double targetTemperatureCelsius;

  /// The current core temperature in Celsius from the virtual sensors.
  ///
  /// This represents the probe's current reading from the virtual core temperature sensor at the time the prediction
  /// was generated. May be null if virtual sensor data is not yet available.
  final double? currentCoreTempCelsius;

  /// The SDK's estimated core temperature in Celsius for prediction calculations.
  ///
  /// This is the probe's internal estimate of the core temperature used specifically for prediction algorithms. This
  /// may differ slightly from currentCoreTempCelsius as it is optimized for prediction accuracy rather than instant
  /// reading.
  final double estimatedCoreTemperature;

  /// The percentage of cooking progress from 0 to 100.
  ///
  /// This value indicates how far through the cooking process the food is, based on the starting temperature, current
  /// temperature, and target temperature. A value of 0 indicates cooking has just started, while 100 indicates the
  /// target temperature has been reached.
  final int percentThroughCook;

  /// The current state of the probe's prediction system.
  ///
  /// This indicates what phase of cooking the probe is in (e.g., probeNotInserted, cooking, predicting) and affects
  /// the reliability and availability of predictions.
  final PredictionState predictionState;

  /// The prediction mode configured for the probe.
  ///
  /// This determines what type of predictions the probe will generate (e.g., timeToRemoval, removalAndResting).
  final PredictionMode predictionMode;

  /// The type of prediction currently being generated.
  ///
  /// This indicates which phase of the cooking process the current prediction applies to (e.g., removal, resting).
  final PredictionType predictionType;

  /// Whether the prediction is considered reliable based on current data quality.
  ///
  /// Predictions may be unreliable during the initial cooking phase when temperature trends are not yet established,
  /// if the probe is not inserted, or if the probe is experiencing connectivity issues.
  final bool isReliable;

  /// The timestamp when this prediction was generated.
  ///
  /// Used to determine the freshness of prediction data and for debugging prediction accuracy over time.
  final DateTime timestamp;

  /// Creates a [PredictionInfo] instance with the specified prediction data.
  ///
  /// The [targetTemperatureCelsius], [estimatedCoreTemperature], [percentThroughCook], [predictionState],
  /// [predictionMode], [predictionType], [isReliable], and [timestamp] parameters are required. Other parameters are
  /// nullable to handle cases where specific data points are not yet available.
  const PredictionInfo({
    required this.targetTemperatureCelsius,
    required this.estimatedCoreTemperature,
    required this.percentThroughCook,
    required this.predictionState,
    required this.predictionMode,
    required this.predictionType,
    required this.isReliable,
    required this.timestamp,
    this.estimatedTimeSeconds,
    this.currentCoreTempCelsius,
  });

  /// Creates a [PredictionInfo] instance from a map received via platform channels.
  ///
  /// This factory constructor handles the conversion from native platform data to the Dart model, including proper type
  /// casting, null handling, and enum conversion.
  ///
  /// Expected map structure:
  ///
  /// ```json
  /// {
  ///   "estimatedTimeSeconds": 1800,
  ///   "targetTemperatureCelsius": 65.0,
  ///   "currentCoreTempCelsius": 45.0,
  ///   "estimatedCoreTemperature": 45.5,
  ///   "percentThroughCook": 60,
  ///   "predictionState": "Cooking",
  ///   "predictionStateRaw": 2,
  ///   "predictionMode": "Time to Removal",
  ///   "predictionModeRaw": 1,
  ///   "predictionType": "Removal",
  ///   "predictionTypeRaw": 1,
  ///   "isReliable": true,
  ///   "timestampMillis": 1640995200000
  /// }
  /// ```
  factory PredictionInfo.fromMap(Map<String, dynamic> map) {
    final int? timestampMillis = map['timestampMillis'] as int?;
    final DateTime timestamp = timestampMillis != null
        ? DateTime.fromMillisecondsSinceEpoch(timestampMillis)
        : DateTime.now();

    // Parse prediction state from raw value (preferred) or string fallback
    final PredictionState predictionState;
    if (map['predictionStateRaw'] != null) {
      predictionState = PredictionState.fromInt(
        map['predictionStateRaw'] as int,
      );
    } else if (map['predictionState'] != null) {
      predictionState = PredictionState.fromString(
        map['predictionState'] as String,
      );
    } else {
      predictionState = PredictionState.unknown;
    }

    // Parse prediction mode from raw value (preferred) or string fallback
    final PredictionMode predictionMode;
    if (map['predictionModeRaw'] != null) {
      predictionMode = PredictionMode.fromInt(map['predictionModeRaw'] as int);
    } else if (map['predictionMode'] != null) {
      predictionMode = PredictionMode.fromString(
        map['predictionMode'] as String,
      );
    } else {
      predictionMode = PredictionMode.none;
    }

    // Parse prediction type from raw value (preferred) or string fallback
    final PredictionType predictionType;
    if (map['predictionTypeRaw'] != null) {
      predictionType = PredictionType.fromInt(map['predictionTypeRaw'] as int);
    } else if (map['predictionType'] != null) {
      predictionType = PredictionType.fromString(
        map['predictionType'] as String,
      );
    } else {
      predictionType = PredictionType.none;
    }

    return PredictionInfo(
      estimatedTimeSeconds: map['estimatedTimeSeconds'] as int?,
      targetTemperatureCelsius: (map['targetTemperatureCelsius'] as num)
          .toDouble(),
      currentCoreTempCelsius: (map['currentCoreTempCelsius'] as num?)
          ?.toDouble(),
      estimatedCoreTemperature: (map['estimatedCoreTemperature'] as num)
          .toDouble(),
      percentThroughCook: map['percentThroughCook'] as int,
      predictionState: predictionState,
      predictionMode: predictionMode,
      predictionType: predictionType,
      isReliable: map['isReliable'] as bool? ?? false,
      timestamp: timestamp,
    );
  }
}
